  VALUES (v_test_id, v_topic_id, 'For care involving CK-MM limitation, which statements are correct? (Select all that apply)', 'For care involving CK-MM limitation, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "CK-MM can rise in rhabdomyolysis."}, {"id": "b", "text": "CK-MM is most cardiac-specific marker in this note."}, {"id": "c", "text": "CK-MM is not cardiac-specific in this note."}, {"id": "d", "text": "CK-MM excludes muscle injury in this note."}, {"id": "e", "text": "CK-MM source is skeletal muscle."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: CK-MM reflects skeletal muscle injury such as rhabdomyolysis and is not cardiac-specific.', 'Cardiac Biomarkers - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans management around CK-BB limitation. Which items belong in the plan? (Select all that apply)', 'The nurse plans management around CK-BB limitation. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "CK-BB is linked to brain/smooth muscle."}, {"id": "b", "text": "CK-BB is preferred biomarker for MI in this note."}, {"id": "c", "text": "CK-BB can relate to bowel infarction in note."}, {"id": "d", "text": "CK-BB comes from ventricular myocardium in this note."}, {"id": "e", "text": "CK-BB is not cardiac marker of choice."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: CK-BB is associated with brain/smooth muscle injury and is not used for cardiac monitoring.', 'Cardiac Biomarkers - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support BNP physiology? (Select all that apply)', 'During reassessment, which observations support BNP physiology? (Select all that apply)', '[{"id": "a", "text": "Ventricular stretch triggers BNP release."}, {"id": "b", "text": "Volume overload increases BNP."}, {"id": "c", "text": "BNP rises only from skeletal injury in this note."}, {"id": "d", "text": "BNP reflects wall stress in this note."}, {"id": "e", "text": "BNP is unrelated to ventricular stretch in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: BNP is released from ventricular myocytes when stretched by volume overload.', 'Cardiac Biomarkers - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with BNP ranges in this note? (Select all that apply)', 'Which cues are consistent with BNP ranges in this note? (Select all that apply)', '[{"id": "a", "text": "BNP <20 defines severe HF in this note."}, {"id": "b", "text": "BNP >400 excludes HF in this note."}, {"id": "c", "text": "100–400 suggests possible HF."}, {"id": "d", "text": "BNP <100 is normal in this note."}, {"id": "e", "text": ">400 suggests likely HF exacerbation."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: BNP normal is <100 pg/mL; 100–400 possible HF; >400 likely HF exacerbation.', 'Cardiac Biomarkers - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for BNP clinical use. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for BNP clinical use. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Higher BNP correlates with worse prognosis."}, {"id": "b", "text": "BNP can separate cardiac vs pulmonary dyspnea causes."}, {"id": "c", "text": "BNP has no prognostic value in this note."}, {"id": "d", "text": "BNP confirms MI infarct size directly in this note."}, {"id": "e", "text": "BNP helps guide diuretic and discharge decisions."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: BNP helps differentiate cardiac from pulmonary dyspnea, guides diuresis/discharge, and higher BNP suggests worse prognosis.', 'Cardiac Biomarkers - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving BNP not MI marker, which statements are correct? (Select all that apply)', 'For care involving BNP not MI marker, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "BNP indicates volume overload, not infarction specificity."}, {"id": "b", "text": "BNP is the most specific MI marker in this note."}, {"id": "c", "text": "BNP rise alone proves STEMI in this note."}, {"id": "d", "text": "BNP is HF-oriented biomarker in note."}, {"id": "e", "text": "Troponin remains MI marker priority."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: The note explicitly states BNP does not indicate MI; it indicates fluid overload/heart failure context.', 'Cardiac Biomarkers - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans management around NT-proBNP reference. Which items belong in the plan? (Select all that apply)', 'The nurse plans management around NT-proBNP reference. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "NT-proBNP has shorter half-life than BNP in this note."}, {"id": "b", "text": "NT-proBNP interpretation differs from BNP thresholds."}, {"id": "c", "text": "NT-proBNP normal is <30 in this note."}, {"id": "d", "text": "NT-proBNP reference <300 is listed."}, {"id": "e", "text": "Longer half-life is noted."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: NT-proBNP normal is listed as <300 pg/mL and has longer half-life.', 'Cardiac Biomarkers - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Myoglobin kinetics? (Select all that apply)', 'During reassessment, which observations support Myoglobin kinetics? (Select all that apply)', '[{"id": "a", "text": "Myoglobin stays elevated 10 days in this note."}, {"id": "b", "text": "Normalization occurs by about 24 hours."}, {"id": "c", "text": "Myoglobin rises after troponin peak in this note."}, {"id": "d", "text": "Myoglobin is earliest riser in note."}, {"id": "e", "text": "Rise occurs 1–3 hours."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Myoglobin rises first at 1–3h after MI but normalizes quickly within 24h.', 'Cardiac Biomarkers - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Myoglobin limitation/use in this note? (Select all that apply)', 'Which cues are consistent with Myoglobin limitation/use in this note? (Select all that apply)', '[{"id": "a", "text": "Myoglobin comes from skeletal and cardiac muscle."}, {"id": "b", "text": "Normal early myoglobin lowers immediate MI likelihood."}, {"id": "c", "text": "Myoglobin alone confirms MI in this note."}, {"id": "d", "text": "Specificity is limited in this note."}, {"id": "e", "text": "Myoglobin is highly cardiac-specific in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Myoglobin is not cardiac-specific and is used mainly for early rule-out when normal at around 3h.', 'Cardiac Biomarkers - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Timeline comparison. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Timeline comparison. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Troponin persists the longest."}, {"id": "b", "text": "CK-MB clears before troponin."}, {"id": "c", "text": "Troponin clears before CK-MB in this note."}, {"id": "d", "text": "Myoglobin rises earliest in this note."}, {"id": "e", "text": "Myoglobin persists longest in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Timeline summary: myoglobin earliest/shortest, CK-MB intermediate, troponin longest duration.', 'Cardiac Biomarkers - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving BUN/creatinine interpretation, which statements are correct? (Select all that apply)', 'For care involving BUN/creatinine interpretation, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Normal creatinine excludes dehydration in this note."}, {"id": "b", "text": "BUN normal range 7–20 is listed."}, {"id": "c", "text": "High BUN with normal creatinine proves MI in this note."}, {"id": "d", "text": "Creatinine normal 0.6–1.2 is listed."}, {"id": "e", "text": "High BUN + high creatinine suggests renal impairment."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: BUN 7–20 and creatinine 0.6–1.2 are listed normal; high BUN with normal creatinine suggests dehydration, while both high suggest renal impairment.', 'Cardiac Biomarkers - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans management around Low-output renal effect. Which items belong in the plan? (Select all that apply)', 'The nurse plans management around Low-output renal effect. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Cardiorenal relationship is explicitly noted."}, {"id": "b", "text": "Renal markers may rise in low-output states."}, {"id": "c", "text": "BUN/Cr are unrelated to hemodynamics in this note."}, {"id": "d", "text": "Renal perfusion is unaffected by cardiac output in this note."}, {"id": "e", "text": "Low cardiac output can impair renal perfusion."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Reduced cardiac output can increase BUN/creatinine due to renal hypoperfusion.', 'Cardiac Biomarkers - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Lactate and ABG significance? (Select all that apply)', 'During reassessment, which observations support Lactate and ABG significance? (Select all that apply)', '[{"id": "a", "text": "Lactate <0.2 is the shock threshold in this note."}, {"id": "b", "text": "Metabolic acidosis can occur in shock/MI."}, {"id": "c", "text": "ABG/lactate assist shock severity assessment."}, {"id": "d", "text": "Lactate >2 indicates hypoperfusion in note."}, {"id": "e", "text": "ABG is irrelevant in shock in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Shock/MI may show metabolic acidosis; lactate >2 mmol/L indicates tissue hypoperfusion and helps gauge shock severity.', 'Cardiac Biomarkers - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Lipid panel targets in this note? (Select all that apply)', 'Which cues are consistent with Lipid panel targets in this note? (Select all that apply)', '[{"id": "a", "text": "Total cholesterol target <200 is listed."}, {"id": "b", "text": "LDL >160 is optimal in high-risk in this note."}, {"id": "c", "text": "HDL under 20 is protective in this note."}, {"id": "d", "text": "HDL >60 is protective per note."}, {"id": "e", "text": "LDL <70 is listed for high-risk."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Desired lipids listed are total cholesterol <200, LDL <70 in high-risk patients, and HDL >60 as protective.', 'Cardiac Biomarkers - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for NCLEX synthesis. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for NCLEX synthesis. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "BNP and myoglobin have distinct non-overlapping roles."}, {"id": "b", "text": "Myoglobin is best reinfarction marker in this note."}, {"id": "c", "text": "Troponin is top MI marker in NCLEX summary."}, {"id": "d", "text": "CK-MB favored for reinfarction detection."}, {"id": "e", "text": "BNP replaces troponin for MI confirmation in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: NCLEX summary: Troponin is gold standard and longest-lasting, CK-MB best for reinfarction, BNP for HF dyspnea differentiation, myoglobin earliest but nonspecific.', 'Cardiac Biomarkers - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Biomarker purpose, which statements are correct? (Select all that apply)', 'For care involving Biomarker purpose, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Biomarkers rise when cardiac cells are damaged."}, {"id": "b", "text": "They assess cardiac stress patterns."}, {"id": "c", "text": "They assist MI and HF evaluation."}, {"id": "d", "text": "Cardiac injury does not alter biomarker levels in this note."}, {"id": "e", "text": "Biomarkers only diagnose pulmonary embolism in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Cardiac biomarkers are blood proteins released after cardiac cell injury and are used for MI/HF diagnosis and stress assessment.', 'Cardiac Biomarkers - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans management around Serial testing principle. Which items belong in the plan? (Select all that apply)', 'The nurse plans management around Serial testing principle. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "One elevated value always confirms MI in this note."}, {"id": "b", "text": "Single value alone is insufficient for MI confirmation."}, {"id": "c", "text": "Rise-and-fall pattern supports MI."}, {"id": "d", "text": "Serial testing is unnecessary in acute chest pain in this note."}, {"id": "e", "text": "Serial q3–6h testing is listed."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Serial values every 3–6 hours are needed, and a rise-and-fall pattern supports MI rather than one isolated elevation.', 'Cardiac Biomarkers - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Troponin priority? (Select all that apply)', 'During reassessment, which observations support Troponin priority? (Select all that apply)', '[{"id": "a", "text": "Troponin has highest NCLEX priority in this section."}, {"id": "b", "text": "Troponin is both highly sensitive and specific in note."}, {"id": "c", "text": "Myoglobin is more specific than troponin in this note."}, {"id": "d", "text": "Troponin is gold standard for MI in this note."}, {"id": "e", "text": "BNP is the gold standard for MI in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Troponin is the most specific and sensitive biomarker for MI and is the gold standard in this note.', 'Cardiac Biomarkers - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Troponin I kinetics in this note? (Select all that apply)', 'Which cues are consistent with Troponin I kinetics in this note? (Select all that apply)', '[{"id": "a", "text": "Troponin I can stay elevated for 7–10 days."}, {"id": "b", "text": "Troponin I peak occurs at 2 hours in this note."}, {"id": "c", "text": "Troponin I rises at 3–6 hours."}, {"id": "d", "text": "Troponin I normalizes within 12 hours in this note."}, {"id": "e", "text": "Peak is 12–24 hours."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Troponin I normal is <0.04 ng/mL, rises 3–6h, peaks 12–24h, normalizes in 7–10 days.', 'Cardiac Biomarkers - NCLEX', true, 100, 1, true);
